const Q_BIOLOGY_1994=[{"id": "objective>Biology>1994>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The membrane surrounding the vacuole in a plant cell is called the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">plasmalemma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tonoplast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nuclear membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endoplasmic reticulum</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The membrane surrounding the vacuole in a plant cell is called the tonoplast. The tonoplast is a semi-permeable membrane that separates the vacuole's contents from the cytoplasm in a cell. It controls the movement of substances in and out of the vacuole.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>1994>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The smallest living organism which share the characteristics of both living and non-living matter are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bacteria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fungi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">viruses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protozoa</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The smallest living organisms which share the characteristics of both living and non-living matter are viruses. Viruses are considered both living and non-living because they can't reproduce without a host cell, but they can evolve and adapt to their environment. They have genetic material like living organisms, but they lack the cellular structure that is often seen as the basic unit of life.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>1994>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Green plants are distinguished from other living organisms by their ability to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">make use of water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make use of oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respond to sunlight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufactured their own food</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Green plants are distinguished from other living organisms by their ability to manufacture their own food. This process is known as photosynthesis. During photosynthesis, green plants convert light energy, usually from the sun, into chemical energy in the form of glucose or other sugars. This process requires carbon dioxide and water, and it produces oxygen as a byproduct. None of the other options are unique to green plants as many organisms make use of water and oxygen, and many organisms respond to sunlight.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>1994>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The soil swallowed by the earthworm to form the worm cast is grouped up in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">clitellum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prostomium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mouth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gizzard</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The soil swallowed by the earthworm to form the worm cast is ground up in the gizzard. The gizzard is a part of an earthworm's digestive system. After the soil is ingested, it passes through the esophagus and into the crop, where it is stored. From the crop, the soil moves into the gizzard. The gizzard uses stones that the earthworm eats to grind the soil into smaller pieces. The other options (clitellum, prostomium, mouth) are parts of the earthworm's body but they do not play a role in grinding up the soil.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1994>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which is the correct order in an evolutionary sequence for the following plants groups?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bacteria → ferns → algae → mosses → seed plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bacteria → ferns → mosses → algae → seed plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bacteria → algae → mosses → ferns → seed plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bacteria → mosses → algae → ferns → seed plants</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct order of evolution in plant groups is Bacteria → algae → mosses → ferns → seed plants. Bacteria are the most primitive organisms. Algae, being simple aquatic plants, evolved next. Mosses are more complex than algae and are the first true plants. Ferns, which are vascular plants, evolved from mosses. Finally, seed plants, which are the most complex plants, evolved from ferns.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>1994>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Amoeba, osmoregulation is carried out by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pseudopodium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">food vacuole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contractile vacuole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleus</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Amoeba, osmoregulation is carried out by the contractile vacuole. Osmoregulation is the process by which an organism regulates its internal water balance. In the case of Amoeba, the contractile vacuole collects excess water from the cytoplasm and expels it out of the cell, thus maintaining the water balance.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>1994>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question  <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The parts used for feeding is labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">K is used for feeding. The part used for feeding in a cockroach is the mouth. The cockroach's mouth is located on the underside of its head and is surrounded by a number of mouthparts. These mouthparts are used for chewing and grinding food.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1994>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question  <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The mouth part of the insect is adapted for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> biting and chewing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sucking and chewing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biting and sucking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">piercing and sucking</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">biting and chewing mouth part. Biting and chewing mouthparts are the most common type of mouthpart found in insects. They are also found in other animals, such as spiders, crustaceans, and some fish. <br/>  <br/> Biting and chewing mouthparts are adapted for eating solid food. They typically consist of a pair of hard, biting jaws (mandibles) and a pair of appendages (maxillae) that help to move and manipulate food.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1994>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following combinations differentiates a bony fish from a cartilaginous fish? I. Presence of gills II. Absence of gill slits III. Possession of bony skeleton IV. Possession of laterally compressed body V. Possession of dorso-ventrally compressed body</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> II, III and V</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main differences between bony fish and cartilaginous fish are II. Absence of gill slits III. Possession of bony skeleton IV. Possession of laterally compressed body</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BONY FISH"}, {"id": "objective>Biology>1994>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which is the most important adaptation of a bony fish life in water?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The possession of a streamlined shape</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The presence of overlapping scales</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The covering of the body by thin film of slime</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The possession of a caudal fin</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important adaptation of a bony fish for life in water is the possession of a streamlined shape. This shape reduces the resistance of water, allowing the fish to swim efficiently. Overlapping scales, a thin film of slime, and a caudal fin are also adaptations for life in water, but they are not as crucial as the streamlined shape. The scales and slime protect the fish's body, while the caudal fin aids in propulsion. However, without a streamlined shape, the fish would expend more energy overcoming water resistance, making this the most important adaptation.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1994>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question below <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Which of the labelled parts allows for efficient absorption of water and minerals?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> The part of a plant that provides for effective absorbtion of water is the root hair. Root hairs are tiny, elongated cells that grow from the surface of roots. They are very thin and have a large surface area, which makes them ideal for absorbing water and minerals from the soil.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : ROOT"}, {"id": "objective>Biology>1994>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question below <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> starch is usually stored in the part labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">II. Starch is usually stored in the cortex of a transverse section of a dicotyledonous root. <br/>  <br/> The cortex is the ground tissue region found in monocot and dicot roots, located between the outer epidermis and the inner vascular structures. It is primarily composed of parenchyma cells.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : ROOT"}, {"id": "objective>Biology>1994>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The failure of transport and respiratory systems in plants as well as the presence of reddish colour in stems and leaves result from the deficiency of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">magnesium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potassium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phosphorus</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The deficiency of potassium in plants can lead to the failure of transport and respiratory systems. Potassium is an essential nutrient that plays a key role in many plant processes such as protein synthesis, photosynthesis, water uptake, and transport of sugars and nutrients. It also helps in the opening and closing of stomata, which are tiny openings in the leaf surface that allow for gas exchange. When potassium is deficient, these processes can be impaired, leading to symptoms such as reduced growth, yellowing or reddening of leaves, and poor crop yield.</div>", "topic": "NUTRITION : MINERAL REQUIREMENT"}, {"id": "objective>Biology>1994>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dental formula I=3/3, C=1/1, pm=4/4, m=2/3 is that of a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">goat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rabbit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">man</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dog</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dental formula I=3/3, C=1/1, pm=4/4, m=2/3 is that of a dog. The dental formula represents the number of different types of teeth in one half of the mouth. In this case, the dog has 3 incisors, 1 canine, 4 premolars, and 2/3 molars in one half of the mouth.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1994>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The nitrifying bacteria, Nitrosomonas, convert ammonia to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nitrites</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> nitric acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrous oxide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nitrosomonas is a genus of bacteria that plays a significant role in the nitrogen cycle by oxidizing ammonia into nitrite. This process is known as nitrification. Therefore, the correct answer is nitrites.</div>", "topic": "ECOLOGY : NUTRIENT CYCLING IN NATURE"}, {"id": "objective>Biology>1994>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The activity of ptyalin is likely to decrease with an increase in concentration of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acid</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ptyalin is an enzyme in saliva that breaks down starch into maltose. Its activity is optimal at a neutral or slightly alkaline pH. However, its activity decreases in an acidic environment. Therefore, the correct answer is acid.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>1994>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The phloem parenchyma is sometimes used for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">food storage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supporting the stem</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> production of the sieve tube</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transporting water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Phloem parenchyma, also known as transfer cells and border parenchyma, are located near the finest branches and terminations of sieve tubes in leaf veinlets, where they also function in the transport of foods. However, their primary function is to store food materials such as starch, fats, and other substances. Hence, the correct answer is 'food storage'.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>1994>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process by which a red blood cell placed in distilled water absorbs water until it burst and releases its contents into the surrounding is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">osmosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plasmolysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">turgidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">haemolysis</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a red blood cell is placed in distilled water, it will absorb water due to osmosis until it bursts. This process is known as haemolysis. Osmosis is the movement of water from an area of lower concentration to an area of higher concentration through a semi-permeable membrane. In this case, the red blood cell membrane is the semi-permeable membrane. When the red blood cell absorbs too much water, it bursts, releasing its contents into the surrounding water. This process is known as haemolysis.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>1994>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer  the question <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The most appropriate title for the set up is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quantitative measurement of respiration in plants and animals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">measurement of respiratory rates in living organisms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">comparison between photosynthesis and respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">comparison of respiratory rates in plants and animals</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is comparison of respiratory rates in plants and animals</div>", "topic": "RESPIRATION : AEROBIC RESPIRATION"}, {"id": "objective>Biology>1994>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer  the question <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part labelled j is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">porosimeter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">auxanometer</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Manometer is a device to measure pressures. A common simple manometer consists of a U shaped tube of glass filled with some liquid.</div>", "topic": "RESPIRATION : RESPIRATORY ORGANS AND SURFACES"}, {"id": "objective>Biology>1994>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A circulatory system that does not allow mixing of oxygenated and de-oxygenated blood in mammalian heart is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">open</div>", "<div style=\"font-family:Cambria;font-size:17px;\">haemocoelic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">single</div>", "<div style=\"font-family:Cambria;font-size:17px;\">closed</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The circulatory system that does not allow mixing of oxygenated and de-oxygenated blood in mammalian heart is referred to as a closed circulatory system. In this system, the blood is enclosed in blood vessels and does not mix with the body's interstitial fluid. This is different from an open circulatory system where blood is not always contained within a network of blood vessels.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>1994>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following waste products in plants is excreted through the stomata and lenticels?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Carbon dioxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alkaloids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tannins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Anthocyanins</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In plants, the waste product that is excreted through the stomata and lenticels is Carbon dioxide. Stomata and lenticels are tiny openings or pores in plant tissue that allow for gas exchange. Carbon dioxide is a byproduct of respiration, a process in which plants convert glucose and oxygen into water, carbon dioxide, and energy.</div>", "topic": "EXCRETION : EXCRETORY PRODUCTS OF PLANTS"}, {"id": "objective>Biology>1994>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question below <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The vertebra illustrated is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lumbar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thoracic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">caudal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cervical</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thoracic vertebrae. The vertebrae illustrated is thoracic. The thoracic vertebrae (T1-T12) have the following key features: <br/>  <br/> - Heart-shaped body <br/> - Long, downward-pointing spinous process <br/> - Costal facets for rib attachment <br/> - Long, pointed transverse processes <br/> - Smaller vertebral foramen <br/> - Intervertebral discs for shock absorption and movement <br/> - Short pedicles and broad, flat laminae <br/>  <br/> These features allow the thoracic spine to support the rib cage, facilitate breathing, and provide stability and flexibility to the upper back.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>1994>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question below <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The neural arch is labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">II-Neural arch: the curved rear (dorsal) section of a vertebra, enclosing the canal through which the spinal cord passes. <br/> The neutral arch of the thoracic vertebrae is a gentle, smooth curvature characterized by: <br/>  <br/> - Slight convexity (outward curvature) in the front <br/> - Slight concavity (inward curvature) in the back <br/> - Constant curvature throughout the thoracic region (T1-T12) <br/>  <br/> This natural curvature: <br/>  <br/> - Supports the rib cage and upper back <br/> - Maintains posture and balance <br/> - Distributes mechanical stress and load <br/> - Facilitates movement and flexibility <br/>  <br/> The neutral arch is a crucial aspect of spinal anatomy and function.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>1994>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In animals, meiosis comes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">after fertilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">after ever mitotic division</div>", "<div style=\"font-family:Cambria;font-size:17px;\">before fertilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">before every mitotic division</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In animals, meiosis occurs before fertilization. Meiosis is a type of cell division that reduces the number of chromosomes in the parent cell by half and produces four gamete cells. This process is required to produce egg and sperm cells for sexual reproduction. Therefore, it comes before fertilization.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>1994>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fleshy base of a flower to which the different floral parts are attached is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">calyx</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sepals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Receptacle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hypothalamus</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fleshy base of a flower to which the different floral parts are attached is known as the Receptacle. It is part of the flower's structure that connects the flower to the stem and holds the flower's major parts. The other options, calyx and sepals, are parts of the flower, and the hypothalamus is a part of the brain, not related to the structure of a flower.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>1994>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a short-sighted person views a distant object without spectacles, the image is formed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">on the retina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">in front of the retina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">behind the retina</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> on the blind spot</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Short-sightedness, also known as myopia, is a common vision condition in which you can see objects near to you clearly, but objects farther away are blurry. This happens when the light that enters the eye does not focus on the retina but instead is focused in front of the retina. This is usually because the eyeball is too long or the cornea (the clear front cover of the eye) is too curved for the length of the eyeball.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>1994>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The graph above shows the relationship between the body and atmospheric temperature for dog and lizard. What is the most appropriate deduction that could be made from the graph?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lizards are more likely to survive hazards than dogs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both animals maintain a constant body temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The dog's body temperature is independent of the external temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The lizard's body temperature varies with that of the dog</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dog's body temperature is independent of the external temperature. <br/> Dogs regulate their body temperature internally, regardless of external temperatures, through: <br/>  <br/> - Insulation (fur) <br/> - Metabolic heat generation <br/> - Hypothalamic thermostat <br/> - Blood vessel dilation/constriction <br/> - Panting (evaporative cooling) <br/> - Behavioral adaptations (seeking shade, burrowing, activity adjustment) <br/>  <br/> These mechanisms maintain a stable body temperature (around 100.5-102.5°F), ensuring proper bodily functions and health.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>1994>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the brain that controls heart beat and breathing is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">olfactory lobe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cerebellum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cerebral hemisphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">medulla oblongata</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The medulla or the midbrain is responsible for important bodily functions such as heartbeat and breathing, It is also responsible for hand-eye coordination and depth perception.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>1994>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the list of ecological constituents below to answer the question below <br/> 1. Mango 2. Spear grass 3. Goat 4. Sheep 5. Temperature 6. Beans 7. Rock 8. Water <br/>  <br/> Items 1-4 can be regarded as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a community</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> an ecosystem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a niche</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The items 1-4 (Mango, Spear grass, Goat, Sheep) can be regarded as a community. In ecology, a community is a group of different species that live together in a location. In this case, Mango and Spear grass are plant species, while Goat and Sheep are animal species. They can coexist in the same environment, forming a community.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>1994>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the list of ecological constituents below to answer the question below <br/> 1. Mango 2. Spear grass 3. Goat 4. Sheep 5. Temperature 6. Beans 7. Rock 8. Water <br/> The physical factors are represented by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1, 5, 6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4, 5, 7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5, 7, 8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6, 7, 8</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The physical factors in the list are represented by items 5 (Temperature), 7 (Rock), and 8 (Water). In ecology, physical factors, also known as abiotic factors, refer to the non-living components of an ecosystem that influence the living organisms (biotic factors). These include temperature, water, and rocks among others.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>1994>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following sets is made up of decomposers?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Rhizopus, earthworm and protozoa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mushroom, rhizopus and bacteria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bacteria, earthworm and nematodes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">earthworm, sedges and platyhelminthes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Decomposers are organisms that break down dead or decaying organisms, and in doing so, they carry out the natural process of decomposition. Mushrooms, rhizopus (a type of fungus), and bacteria are all decomposers. They break down organic material and return nutrients to the soil, aiding in the cycle of matter. Earthworms, on the other hand, are more accurately described as detritivores, which consume decaying organic material but do not break it down at a microscopic level like decomposers do.</div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>1994>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct order in a food chain involving the organisms (1)Grasses, (2)Hawks, (3)Snakes, (4)Grasshopper, (5)Lizards is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1 2 3 4 5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 4 3 2 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 4 5 3 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 2 4 5 1</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A food chain represents the flow of energy and nutrients from one trophic level to the next, starting with a producer and ending with a top predator. In this case, the correct order would be: Grasses (1, producer) -> Grasshopper (4, primary consumer) -> Lizards (5, secondary consumer) -> Snakes (3, tertiary consumer) -> Hawks (2, quaternary consumer). This order represents the flow of energy from the producer to the top predator.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>1994>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organisms with the least number of individuals in a pyramid of numbers are the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">secondary consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tertiary consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary consumers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a pyramid of numbers, the tertiary consumers are at the top and have the least number of individuals. This is because each level of the pyramid represents the number of organisms at that trophic level in an ecosystem. The primary producers are at the bottom of the pyramid and have the most individuals, followed by the primary consumers, then the secondary consumers, and finally the tertiary consumers at the top with the least individuals. This is due to the energy loss that occurs at each trophic level.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>1994>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the list of biomes below to answer the question below <br/> 1. Desert 2. Rain forest 3. Southern Guinea savannah 4. Northern Guinea savannah <br/>  <br/> A biome with a low annual rainfall, few scattered trees within dense layer of grasses and found in Kano and Katsina States</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The description given in the question matches the characteristics of the Northern Guinea savannah. This biome is characterized by a low annual rainfall, few scattered trees within a dense layer of grasses, and is found in Kano and Katsina States in Nigeria. The other options do not match this description. The desert (option 1) has very little rainfall and sparse vegetation. The rainforest (option 2) has high rainfall and dense vegetation. The Southern Guinea savannah (option 3) has more trees and higher rainfall than the Northern Guinea savannah.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : SUDAN SAVANNA"}, {"id": "objective>Biology>1994>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the list of biomes below to answer the question below <br/> 1. Desert 2. Rain forest 3. Southern Guinea savannah 4. Northern Guinea savannahA biome where there are many cacti and the small mammals undergo aestivation for long periods is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The description given in the question matches the characteristics of a desert biome. Cacti are plants adapted to desert conditions, and small mammals in deserts often undergo aestivation, a state of dormancy, during the hot and dry periods to conserve water and energy.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : DESERT"}, {"id": "objective>Biology>1994>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ecological succession ends with the formation of a stable</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">niche</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pioneer community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">climax community</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ecological succession refers to the process of change in the species structure of an ecological community over time. It ends with the formation of a stable climax community. A climax community is a stable and mature end stage of succession where the species composition remains relatively unchanged until a disturbance occurs.</div>", "topic": "THE ECOLOGY OF POPULATIONS : ECOLOGICAL SUCCESSION"}, {"id": "objective>Biology>1994>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a drought situation, plants suffer from water stress which could result in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> reduced biochemical activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enhanced chemical activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enhanced microbial activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced phototropic activities</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a drought situation, plants suffer from water stress which could result in reduced biochemical activities. Biochemical activities in plants are dependent on water. In the absence of adequate water, these activities slow down or stop, leading to reduced growth and productivity.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1994>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The water retention capacity of a soil indicates its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fertility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capillarity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aeration level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pH level</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The water retention capacity of a soil indicates its capillarity. Capillarity refers to the ability of a porous material (in this case, soil) to draw in and hold a liquid (in this case, water). Soils with high capillarity can retain more water, which is beneficial for plant growth.</div>", "topic": "SOIL : SOIL FERTILITY"}, {"id": "objective>Biology>1994>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">People who suck petrol with their mouths run the risk of increasing in their blood the concentration of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnesium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Petrol contains lead as an additive. When people suck petrol with their mouths, they run the risk of increasing the concentration of lead in their blood. Lead is a toxic metal that can cause serious health problems when it builds up in the body.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>1994>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference and similarities among living things account for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diversity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evolution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The differences and similarities among living things account for evolution. Organic evolution is define as the sum total of adaptive changes from old form that have taken place over a long time, resulting in diversity of forms, structures and functions among organisms.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>1994>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">People with sickle-cell anaemia have haemoglobin</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">S and are homozygous recessive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A and are heterozygous recessive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">S and are heterozygous recessive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A and are homozygous recessive</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">People with sickle-cell anaemia have haemoglobin S and are homozygous recessive. Sickle cell anemia is a genetic disease that causes the red blood cells to become misshapen and break down. It is caused by a mutation in the HBB gene which codes for a protein called beta-globin, a component of hemoglobin. This mutation results in the production of an abnormal version of beta-globin called hemoglobin S or HbS. When a person has two HbS genes, Hemoglobin SS, the disease is called sickle cell anemia. This is the case for people who are homozygous for the HbS allele.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1994>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the gene locus for eye colour in humans, the allele for brown eye is dominant over the allele for blue eyes. If a homozygous brown-eyed girl has a brother with blue eyes, what are the likely phenotypes of their parents'eye colour (Eye colour is not a sex linked trait)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Both parents have blue eyes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their father has blue eyes and their mother has brown eyes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both parents have brown eyes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their mother has the blue eyes and their father has the brown eyes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In this case, the girl is homozygous for the brown eye allele (BB) and the boy is homozygous for the blue eye allele (bb). Since eye color is not a sex-linked trait, it means that both parents must be heterozygous (Bb) for them to have a child with blue eyes and a child with brown eyes. Therefore, both parents have brown eyes because the brown eye allele is dominant over the blue eye allele.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1994>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a woman's genotype is Tt Qq Rr, what would be the gene content of her eggs?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">TQr, tqr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">TQR, tqr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">TqR, tQr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tQr, TQR</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">TQR, tqr <br/> A woman's genotype Tt Qq Rr would produce eggs with the gene content TQR, tqr. This is because during meiosis, the alleles for each gene separate so that each egg carries one allele for each gene.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1994>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sex-linked defect in which very slight cut produces severe bleeding is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">anaemia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anorexia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">haemophilia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">haemolysis</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Haemophilia is a sex-linked genetic disorder that impairs the body's ability to make blood clots, a process needed to stop bleeding. This results in people bleeding longer after an injury, easy bruising, and an increased risk of bleeding inside joints or the brain. Therefore, the correct answer is haemophilia.</div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}, {"id": "objective>Biology>1994>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man who has the trait for colour blindness marries a normal woman. What percentage of their children would be sufferers, carriers and normal respectively</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0%, 50% and 50%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25%, 50% and 25%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50%, 25% and 25%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25%, 37.5% and 37.5%</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Colour blindness is a sex-linked recessive trait. This means that it is carried on the X chromosome. A man has one X and one Y chromosome, while a woman has two X chromosomes. If a man has the trait for colour blindness, his X chromosome carries the gene for colour blindness. When he has children with a normal woman (who does not carry the gene for colour blindness), their male children will not be colour blind because they receive their X chromosome from their mother. Their female children will be carriers of the trait because they receive one X chromosome from each parent. Therefore, 0% of their children would be sufferers, 50% would be carriers (all females), and 50% would be normal (all males).</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>1994>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Breathing root is an adaptation for survival in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mangrove swamp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">desert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arboreal habitat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">savanna</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Breathing roots, also known as pneumatophores, are a type of aerial root that enables a plant to absorb oxygen from the air. This adaptation is commonly found in plants that live in waterlogged soils or mangrove swamps where the soil is poorly oxygenated. Therefore, breathing roots are an adaptation for survival in the mangrove swamp.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1994>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Red coloration on the head of a male lizard helps it to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> mark its territory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">camouflage in the enviroment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secure its mate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">defend itself</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The red coloration on the head of a male lizard is a form of sexual dimorphism, which is a physical difference between males and females of the same species. In this case, the red coloration is used to attract a mate, making option 3 the correct answer.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>1994>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A phenomenon by which an animal goes into a state of dormancy during the dry season is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hibernation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aestivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">incubation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deactivation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aestivation, also spelled estivation, is a state of animal dormancy, similar to hibernation, characterized by inactivity and a lowered metabolic rate, that is entered in response to high temperatures and arid conditions. It takes place during times of heat and dryness, the hot dry season, which are often the summer months. In contrast to hibernation, when animals slow their metabolic rate to save energy and avoid the cold, aestivation is performed to avoid the extreme heat and dryness of summer. This can be seen in many desert animals.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>1994>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The anatomical evidence usually used in support of the evolutionary relationship among whales, human, birds, and dogs is the possession of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thick skin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pentadactyl limb</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tail</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> epidermal structure</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pentadactyl limb is an anatomical structure in the limbs of many vertebrates. It is named after the five digits (fingers or toes) that are part of the structure. This structure is evidence of common ancestry among many vertebrates, including whales, humans, birds, and dogs. The other options do not provide evidence of common ancestry.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}];
